const input = $('⚡ Entry').item.json;
return [{ json: {
  new_post_id:    input.post_id    || '',
  new_post_title: input.post_title || '',
  new_post_url:   input.post_url   || '',
  new_keyword:    input.keyword    || ''
}}];

const posts      = Array.isArray($input.first().json) ? $input.first().json : [];
const newData    = $('📥 Get New Post Data').item.json;
const newTitle   = (newData.new_post_title || '').toLowerCase();
const newKw      = (newData.new_keyword    || '').toLowerCase();
const newId      = parseInt(newData.new_post_id);

// Find older posts where content is topically related to new post keyword
const candidates = posts
  .filter(p => p.id !== newId)
  .map(p => {
    const content = (p.content?.rendered || '').replace(/<[^>]*>/g, ' ').toLowerCase();
    const title   = (p.title?.rendered   || '').toLowerCase();
    const url     = p.link || '';
    const pid     = p.id;

    // Score: does the old post mention the new keyword?
    const kwHits    = (content.match(new RegExp(newKw.replace(/[^a-z0-9 ]/g,'\\$&'), 'g')) || []).length;
    const titleHit  = title.includes(newKw) ? 5 : 0;
    const score     = kwHits + titleHit;

    return { pid, title: p.title?.rendered || '', url, content_preview: content.substring(0, 500), score };
  })
  .filter(p => p.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, 8);

return [{ json: { candidates, new_post: newData, total_candidates: candidates.length } }];

