const raw  = $input.first().json.message?.content || '[]';
const data = $('🧠 Find Link Candidates').item.json;
let links  = [];
try {
  const match = raw.match(/\[([\s\S]*?)\](?!\s*[a-z])/i);
  links = JSON.parse(match ? '[' + match[1] + ']' : raw);
} catch(e) {
  links = data.candidates.slice(0,3).map(c => ({
    post_id: c.pid, post_title: c.title, post_url: c.url,
    anchor_text: data.new_post.new_keyword,
    suggested_placement: 'Add near first mention of ' + data.new_post.new_keyword
  }));
}

// Build Telegram message for review
const lines = links.map((l, i) =>
  `${i+1}. <b>${l.post_title}</b>\n   Anchor: "${l.anchor_text}"\n   Where: ${l.suggested_placement?.substring(0, 80)}...\n   Post: ${l.post_url}`
).join('\n\n');

const msg = `🔗 <b>Internal Linking Suggestions</b>\n\nNew article: <b>${data.new_post.new_post_title}</b>\n\n${links.length} posts to update:\n\n${lines}\n\n📋 Full details saved to Internal Links Log sheet.`;

return [{ json: {
  links,
  telegram_message: msg,
  new_post: data.new_post,
  chat_id: $('⚙️ Load Config').item.json.TELEGRAM_CHAT_ID || $vars.TELEGRAM_CHAT_ID
}}];

const d = $input.first().json;
return (d.links || []).map(l => ({ json: {
  New_Article_Title:   d.new_post.new_post_title,
  New_Article_URL:     d.new_post.new_post_url,
  Target_Post_ID:      l.post_id,
  Target_Post_Title:   l.post_title,
  Target_Post_URL:     l.post_url,
  Anchor_Text:         l.anchor_text,
  Suggested_Placement: l.suggested_placement,
  Status:              'Pending',
  Date_Suggested:      new Date().toISOString().split('T')[0]
}}));
